        NDS_VEC_VSETVLI(vl, col_count, NDS_VEC_VTYPE_SEW_E8, NDS_VEC_VTYPE_LMUL_M1);
        NDS_VEC_VLE8_V(NDS_VEC_V24, ptr_a0);
        NDS_VEC_VLE8_V(NDS_VEC_V25, ptr_a1);
        NDS_VEC_VLE8_V(NDS_VEC_V26, ptr_a2);
